function interpolate(template, ctx) {
  return template.replace(/\{name\}/g, ctx.name).replace(/\{completedCount\}/g, String(ctx.completedCount)).replace(/\{targetCount\}/g, String(ctx.targetCount)).replace(/\{completedDays\}/g, String(ctx.completedDays)).replace(/\{streak\}/g, String(ctx.streak)).replace(/\{bodyCount\}/g, String(ctx.bodyCount)).replace(/\{mindCount\}/g, String(ctx.mindCount)).replace(/\{spiritCount\}/g, String(ctx.spiritCount)).replace(/\{damage\}/g, String(ctx.damage)).replace(/\{neglectedCategory\}/g, ctx.neglectedCategory).replace(/\{strongCategory\}/g, ctx.strongCategory).replace(/\{skippedActivity\}/g, ctx.skippedActivity).replace(/\{daysSince\}/g, String(ctx.daysSince)).replace(/\{weekOverWeek\}/g, String(ctx.weekOverWeek)).replace(/\{bestDay\}/g, ctx.bestDay).replace(/\{bossName\}/g, ctx.bossName).replace(/\{bossHpPercent\}/g, String(ctx.bossHpPercent)).replace(/\{chapter\}/g, String(ctx.chapter)).replace(/\{chapterName\}/g, ctx.chapterName).replace(/\{eudaimoniaIndex\}/g, String(ctx.eudaimoniaIndex));
}
function pickRandom(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}
function getPerformanceTier(completionRate) {
  if (completionRate >= 0.8)
    return "positive";
  if (completionRate >= 0.4)
    return "mixed";
  return "negative";
}
function pickDialogue(tier, ctx) {
  let template;
  if (ctx.completionRate >= 1 && ctx.targetCount > 0) {
    template = pickRandom(PERFECT_WEEK_DIALOGUES);
  } else if (ctx.bossHpPercent > 0 && ctx.bossHpPercent < 25) {
    template = pickRandom(BOSS_DIALOGUES);
  } else if (ctx.streak >= 7) {
    template = pickRandom(STREAK_DIALOGUES);
  } else if (ctx.weekOverWeek > 3 && tier !== "negative") {
    template = pickRandom(COMEBACK_DIALOGUES);
  } else if (ctx.eudaimoniaIndex > 0 && ctx.eudaimoniaIndex % 10 < 3 && tier === "positive") {
    template = pickRandom(MILESTONE_DIALOGUES);
  } else {
    const pool = tier === "positive" ? POSITIVE_DIALOGUES : tier === "mixed" ? MIXED_DIALOGUES : NEGATIVE_DIALOGUES;
    template = pickRandom(pool);
  }
  return interpolate(template, ctx);
}
function pickFarewell(name, tier = "mixed") {
  const pool = tier === "positive" ? POSITIVE_FAREWELLS : tier === "negative" ? NEGATIVE_FAREWELLS : NEUTRAL_FAREWELLS;
  const template = pickRandom(pool);
  return template.replace(/\{name\}/g, name);
}

// src/utils/journal.ts
async function createJournalEntry(app, folder, title, content, frontmatter) {
  const normalizedFolder = folder.replace(/\/+$/, "");
  const abstractFolder = app.vault.getAbstractFileByPath(normalizedFolder);
  if (!abstractFolder) {
    await app.vault.createFolder(normalizedFolder);
  }
  const today = (/* @__PURE__ */ new Date()).toISOString().slice(0, 10);
  const baseName = title.trim() || today;
  const sanitized = baseName.replace(/[\\/:*?"<>|]/g, "-");
  let filePath = `${normalizedFolder}/${sanitized}.md`;
  let counter = 1;
  while (app.vault.getAbstractFileByPath(filePath)) {
    counter++;
    filePath = `${normalizedFolder}/${sanitized} (${counter}).md`;
  }
  let body = "";
  if (frontmatter && Object.keys(frontmatter).length > 0) {
    const fmLines = Object.entries(frontmatter).map(([k, v]) => `${k}: ${v}`).join("\n");
    body = `---
${fmLines}
---

`;
  }
  body += content;
  await app.vault.create(filePath, body);
  return filePath;
}
function getRecentJournalEntries(app, folder, limit = 5) {
  const normalizedFolder = folder.replace(/\/+$/, "");
  const files = app.vault.getMarkdownFiles().filter((f) => f.path.startsWith(normalizedFolder + "/")).sort((a, b) => b.stat.mtime - a.stat.mtime).slice(0, limit);
  return files.map((f) => ({
    name: f.basename,
    path: f.path,
    date: new Date(f.stat.mtime).toISOString().slice(0, 10)
  }));
}

